import inspect

def assert_equal(actual, expected):
    assert actual == expected, (
        f"\nExpected:\n{expected}\n\nReceived:\n{actual}"
    )

def assert_parameter_count(func, count):
    params = inspect.signature(func).parameters

    assert len(params) == count, (
        f"{func.__name__}() should accept {count} parameter(s)."
    )

def test_dictionary_exists(solution):
    assert hasattr(solution, "test_settings"), (
        "Dictionary test_settings was not found."
    )

def test_add_setting_exists(solution):
    assert hasattr(solution, "add_setting"), (
        "Function add_setting() was not found."
    )

def test_add_setting_parameters(solution):
    assert_parameter_count(solution.add_setting, 2)

