def test_add_setting_duplicate(solution):
    settings = {
        "theme": "light"
    }

    result = solution.add_setting(settings, ("THEME", "dark"))

    assert_equal(
        result,
        "Setting 'theme' already exists! Cannot add a new setting with this name."
    )

def test_add_setting_success(solution):
    settings = {
        "theme": "light"
    }

    result = solution.add_setting(settings, ("volume", "HIGH"))

    assert_equal(
        result, 
        "Setting 'volume' added with value 'high' successfully!"
    )

    assert settings == {
        "theme": "light",
        "volume": "high"
    }, (
        "Dictionary was not updated correctly."
    )

