def test_update_setting_success(solution):
    settings = {
        "theme": "light"
    }

    result = solution.update_setting(
        settings,
        ("theme", "DARK")
    )

    assert_equal(result, "Setting 'theme' updated to 'dark' successfully!")

    assert settings["theme"] == "dark"

def test_update_setting_missing(solution):
    settings = {
        "theme": "light"
    }

    result = solution.update_setting(
        settings,
        ("volume", "high")
    )

    assert_equal(
        result, 
        "Setting 'volume' does not exist! Cannot update a non-existing setting."
    )

