def test_delete_setting_success(solution):
    settings = {
        "theme": "light"
    }

    result = solution.delete_setting(settings, "theme")

    assert_equal(
        result,
        "Setting 'theme' deleted successfully!"
    )
    assert settings == {}

def test_delete_setting_missing_key(solution):
    settings = {
        "theme": "light"
    }

    result = solution.delete_setting(
        settings, "notifications"
    )

    expected = (
        "Setting not found!"
    )

    assert result == expected

